#include "markforge/markforge.h"
int main(void){ mf_timer_t t; mf_vector_t v; size_t i; mf_ast_t ast; mf_render_output_t out; char *s; const char *doc="# Title\n\nHello **world** with [link](https://example.test).\n\n- item\n- item\n"; mf_timer_start(&t); mf_vector_init(&v); for(i=0U;i<100000U;i++) (void)mf_vector_push(&v,(void*)i); mf_vector_destroy(&v); mf_timer_stop(&t); printf("vector_push_100k %.3f ms\n",mf_timer_elapsed_ms(&t)); mf_timer_start(&t); for(i=0U;i<1000U;i++){ (void)mf_parse_string("bench.md",doc,&ast,NULL,NULL); mf_ast_destroy(&ast);} mf_timer_stop(&t); printf("parse_1k %.3f ms\n",mf_timer_elapsed_ms(&t)); (void)mf_parse_string("bench.md",doc,&ast,NULL,NULL); mf_timer_start(&t); for(i=0U;i<1000U;i++){ mf_render_output_init_memory(&out); (void)mf_render_html(&ast,NULL,&out); s=mf_render_output_take(&out); free(s);} mf_timer_stop(&t); printf("render_html_1k %.3f ms\n",mf_timer_elapsed_ms(&t)); mf_ast_destroy(&ast); return 0; }
